/// Returns the Lebedev quadrature points for the given number of angular points.
pub fn getLebedevGrid(n_angular: usize) []const LebedevPoint {
    return switch (n_angular) {
        6 => &lebedev_6,
        14 => &lebedev_14,
        26 => &lebedev_26,
        50 => &lebedev_50,
        110 => &lebedev_110,
        194 => &lebedev_194,
        302 => &lebedev_302,
        590 => &lebedev_590,
        else => @panic("Unsupported Lebedev grid order"),
    };
}

test "lebedev weights sum to 1" {
    const grids = [_][]const LebedevPoint{
        &lebedev_6,
        &lebedev_14,
        &lebedev_26,
        &lebedev_50,
        &lebedev_110,
        &lebedev_194,
        &lebedev_302,
        &lebedev_590,
    };
    for (grids) |grid| {
        var sum: f64 = 0.0;
        for (grid) |pt| {
            sum += pt.w;
        }
        try std.testing.expectApproxEqAbs(1.0, sum, 1e-14);
    }
}
